import React, { useState, useMemo, useCallback, useRef, useEffect } from 'react';
import { 
  Diamond, Search, Calendar, Users, MapPin, Star, 
  LogOut, Home, BookOpen, Heart, User, Filter,
  ChevronRight, Check, ChevronDown, X
} from 'lucide-react';

// ================= HOTELS DATA =================
const HOTELS_DATA = [
  {
    id: 1,
    name: "Azure Palace",
    location: "Maldives",
    price: 2450,
    rating: 4.9,
    image: "https://images.unsplash.com/photo-1566073771259-6a8506099945?w=800&q=80",
    amenities: ["Ocean View", "Private Pool", "SPA"],
    description: "Experience ultimate luxury in overwater villas.",
    maxGuests: 4,
    roomTypes: ["Overwater Villa", "Beach Suite", "Royal Pavilion"]
  },
  {
    id: 2,
    name: "Nebula Resort",
    location: "Dubai, UAE",
    price: 3200,
    rating: 5.0,
    image: "https://images.unsplash.com/photo-1582719508461-905c673771fd?w=800&q=80",
    amenities: ["City View", "SPA", "Butler Service"],
    description: "Futuristic luxury in Dubai skyline.",
    maxGuests: 3,
    roomTypes: ["Sky Suite", "Panoramic Room"]
  }
];

// ================= FLOATING DATE PICKER =================
const FloatingDatePicker = ({ value, onChange, label, min }) => {
  const [open, setOpen] = useState(false);

  const formatDisplay = (dateStr) => {
    if (!dateStr) return "Select date";
    return new Date(dateStr).toLocaleDateString("en-GB", {
      day: "2-digit",
      month: "short",
      year: "numeric",
    });
  };

  return (
    <div className="relative z-[999]">
      <label className="block text-xs text-gray-500 uppercase mb-1 ml-1">
        {label}
      </label>

      <button
        type="button"
        onClick={() => setOpen(!open)}
        className="w-full pl-4 pr-4 py-3 bg-slate-900/50 border border-white/10 rounded-xl text-left text-white hover:bg-slate-800/50"
      >
        {formatDisplay(value)}
      </button>

      {open && (
        <div className="fixed inset-0 flex items-center justify-center z-[99999] bg-black/60">
          <div className="bg-slate-900 border border-white/10 rounded-2xl p-5 shadow-2xl w-80">
            
            <input
              type="date"
              value={value}
              min={min}
              onChange={(e) => {
                onChange(e.target.value);
                setOpen(false);
              }}
              className="w-full bg-slate-800 text-white p-3 rounded-lg outline-none"
            />

            <button
              onClick={() => setOpen(false)}
              className="mt-4 w-full py-2 text-sm text-gray-300 hover:text-white"
            >
              Close
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

// ================= SIDEBAR =================
const Sidebar = ({ activeTab, setActiveTab, user, onLogout }) => (
  <div className="w-64 bg-slate-900/50 border-r border-white/10 p-6 flex flex-col">
    <div className="flex items-center gap-2 mb-8">
      <Diamond className="w-8 h-8 text-cyan-400" />
      <span className="text-xl font-bold text-transparent bg-gradient-to-r from-cyan-400 to-purple-400 bg-clip-text">
        AI'STAY
      </span>
    </div>

    <nav className="flex-1 space-y-2">
      {[
        { icon: Home, label: "Browse", tab: "browse" },
        { icon: BookOpen, label: "Bookings", tab: "bookings" },
        { icon: Heart, label: "Favorites", tab: "favorites" },
        { icon: User, label: "Profile", tab: "profile" }
      ].map(({ icon: Icon, label, tab }) => (
        <button
          key={tab}
          onClick={() => setActiveTab(tab)}
          className={`flex items-center gap-3 w-full px-4 py-3 rounded-xl ${
            activeTab === tab
              ? "bg-cyan-500/20 text-cyan-400"
              : "text-gray-400 hover:text-white"
          }`}
        >
          <Icon className="w-5 h-5" />
          {label}
        </button>
      ))}
    </nav>

    <button
      onClick={onLogout}
      className="text-red-400 flex items-center gap-2 mt-6"
    >
      <LogOut className="w-4 h-4" /> Logout
    </button>
  </div>
);

// ================= DASHBOARD =================
const Dashboard = ({ user, onLogout }) => {
  const [activeTab, setActiveTab] = useState("browse");
  const [search, setSearch] = useState("");
  const [checkIn, setCheckIn] = useState("");
  const [checkOut, setCheckOut] = useState("");

  const filtered = useMemo(() => {
    return HOTELS_DATA.filter(h =>
      h.name.toLowerCase().includes(search.toLowerCase())
    );
  }, [search]);

  return (
    <div className="flex min-h-screen bg-slate-950 text-white">
      <Sidebar 
        activeTab={activeTab}
        setActiveTab={setActiveTab}
        user={user}
        onLogout={onLogout}
      />

      <div className="flex-1 p-8">
        {activeTab === "browse" && (
          <div className="space-y-6">

            {/* SEARCH */}
            <div className="bg-white/5 p-4 rounded-xl border border-white/10 grid grid-cols-3 gap-4">
              <input
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                placeholder="Search hotels..."
                className="col-span-3 md:col-span-1 bg-slate-900 p-3 rounded-xl"
              />

              {/* FLOATING DATE PICKERS */}
              <FloatingDatePicker
                label="Check In"
                value={checkIn}
                onChange={setCheckIn}
                min={new Date().toISOString().split("T")[0]}
              />

              <FloatingDatePicker
                label="Check Out"
                value={checkOut}
                onChange={setCheckOut}
                min={checkIn || new Date().toISOString().split("T")[0]}
              />
            </div>

            {/* HOTELS */}
            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
              {filtered.map(hotel => (
                <div key={hotel.id} className="bg-slate-900 rounded-xl overflow-hidden">
                  <img src={hotel.image} className="h-40 w-full object-cover" />
                  <div className="p-4">
                    <h3 className="font-bold">{hotel.name}</h3>
                    <p className="text-gray-400 text-sm">{hotel.location}</p>
                    <p className="text-cyan-400 font-bold mt-2">${hotel.price}</p>
                  </div>
                </div>
              ))}
            </div>

          </div>
        )}

        {activeTab === "bookings" && (
          <h2 className="text-2xl font-bold">No bookings yet</h2>
        )}

        {activeTab === "favorites" && (
          <h2 className="text-2xl font-bold">No favorites yet</h2>
        )}

        {activeTab === "profile" && (
          <div>
            <h2 className="text-2xl font-bold">{user?.name}</h2>
            <p className="text-gray-400">{user?.email}</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;
